-        /// Initialize pool
-        pub fn init() Self {
-            return Self{
-                .objects = undefined,
-                .free_list = [_]bool{true} ** capacity,
-                .mutex = std.Thread.Mutex{},
-                .total_acquired = 0,
-                .total_released = 0,
-                .peak_usage = 0,
-                .current_usage = 0,
-            };
-        }
