-            .tasks_stolen = self.tasks_stolen,
-            .tasks_acquired = self.tasks_acquired,
-            .has_machine = self.machine_id != null,
-        };
-    }
-};
-
-/// Processor statistics
-pub const ProcessorStats = struct {
-    id: usize,
-    state: ProcessorState,
-    queue_size: usize,
-    tasks_executed: u64,
-    tasks_stolen: u64,
-    tasks_acquired: u64,
-    has_machine: bool,
-};

