-        // Connect to host
-        const address = try std.net.Address.parseIp(host, port);
-        const stream = try std.net.tcpConnectToAddress(address);
-
-        return .{
-            .stream = stream,
-            .host = host_copy,
-            .port = port,
-            .last_used = std.time.timestamp(),
-            .in_use = false,
-            .allocator = allocator,
