-        for (self.connections.items) |*conn| {
-            if (conn.in_use) {
-                active += 1;
-            } else {
-                idle += 1;
-            }
-        }
-
-        return .{
-            .total = self.connections.items.len,
-            .active = active,
-            .idle = idle,
-            .max = self.max_connections,
-        };
-    }
